// Base REST exception
public class RestException extends RuntimeException {
    private int statusCode;
    private String errorCode;

    public RestException(int statusCode, String errorCode, String message) {
        super(message);
        this.statusCode = statusCode;
        this.errorCode = errorCode;
    }

    public int getStatusCode() { return statusCode; }
    public String getErrorCode() { return errorCode; }
}

// TODO: Create these subclasses:
public class ResourceNotFoundException extends RestException {
    // TODO: Constructor with resourceName and id, status=404, code="NOT_FOUND"
}

public class DuplicateResourceException extends RestException {
    // TODO: Constructor with resourceType and field, status=409, code="DUPLICATE"
}

public class ValidationException extends RestException {
    // TODO: Constructor with fieldName and reason, status=400, code="VALIDATION_ERROR"
}

public class UnauthorizedException extends RestException {
    // TODO: Constructor with action, status=401, code="UNAUTHORIZED"
}

public class ErrorResponse {
    private int status;
    private String code;
    private String message;

    public ErrorResponse(RestException ex) {
        this.status = ex.getStatusCode();
        this.code = ex.getErrorCode();
        this.message = ex.getMessage();
    }

    @Override
    public String toString() {
        return "ErrorResponse{status=" + status + ", code='" + code + "', message='" + message + "'}";
    }
}

public class GlobalExceptionHandler {
    public ErrorResponse handle(RestException ex) {
        System.out.println("Handling exception: " + ex.getClass().getSimpleName());
        return new ErrorResponse(ex);
    }
}

public class Main {
    public static void main(String[] args) {
        GlobalExceptionHandler handler = new GlobalExceptionHandler();

        System.out.println(handler.handle(new ResourceNotFoundException("User", 42)));
        System.out.println(handler.handle(new DuplicateResourceException("User", "email")));
        System.out.println(handler.handle(new ValidationException("age", "must be >= 18")));
        System.out.println(handler.handle(new UnauthorizedException("delete user")));
    }
}

