import java.util.*;

public class ApiError {
    private int status;
    private String error;
    private String message;
    private String timestamp;
    private List<String> details;

    public ApiError(int status, String error, String message) {
        this.status = status;
        this.error = error;
        this.message = message;
        this.timestamp = "2024-01-15T10:30:00";
        this.details = new ArrayList<>();
    }

    public void addDetail(String detail) { details.add(detail); }

    @Override
    public String toString() {
        String base = "ApiError{" + status + " " + error + ": " + message + "}";
        if (!details.isEmpty()) base += " Details: " + details;
        return base;
    }
}

public class GlobalExceptionHandler {

    public ApiError handleNotFoundException(RuntimeException ex) {
        // TODO: Return 404 Not Found error
        return null;
    }

    public ApiError handleBadRequestException(IllegalArgumentException ex) {
        // TODO: Return 400 Bad Request error
        return null;
    }

    public ApiError handleSecurityException(SecurityException ex) {
        // TODO: Return 403 Forbidden error
        return null;
    }

    public ApiError handleGenericException(Exception ex) {
        // TODO: Return 500 Internal Server Error with generic message
        // Do NOT expose internal error details in response
        return null;
    }

    public ApiError dispatch(Exception ex) {
        if (ex instanceof IllegalArgumentException) return handleBadRequestException((IllegalArgumentException) ex);
        if (ex instanceof SecurityException) return handleSecurityException((SecurityException) ex);
        if (ex.getMessage() != null && ex.getMessage().contains("not found")) return handleNotFoundException((RuntimeException) ex);
        return handleGenericException(ex);
    }
}

public class Main {
    public static void main(String[] args) {
        GlobalExceptionHandler handler = new GlobalExceptionHandler();

        System.out.println(handler.dispatch(new RuntimeException("User with id 5 not found")));
        System.out.println(handler.dispatch(new IllegalArgumentException("Invalid email format")));
        System.out.println(handler.dispatch(new SecurityException("Access denied to admin endpoint")));
        System.out.println(handler.dispatch(new RuntimeException("NullPointerException at line 42")));
    }
}

