import java.util.*;

public class ProblemDetail {
    private String type;
    private String title;
    private int status;
    private String detail;
    private String instance;
    private Map<String, Object> extensions = new LinkedHashMap<>();

    public ProblemDetail(String type, String title, int status, String detail, String instance) {
        this.type = type; this.title = title; this.status = status;
        this.detail = detail; this.instance = instance;
    }

    public void addExtension(String key, Object value) { extensions.put(key, value); }

    @Override
    public String toString() {
        String base = "ProblemDetail{type='" + type + "', status=" + status + ", title='" + title + "', detail='" + detail + "'}";
        if (!extensions.isEmpty()) base += " [" + extensions + "]";
        return base;
    }
}

public class ExceptionToProblemMapper {

    public ProblemDetail map(Exception ex, String requestPath) {
        // TODO: Map different exception types to RFC 7807 ProblemDetail
        // IllegalArgumentException -> type=validation, status=400
        // NoSuchElementException -> type=not-found, status=404
        // ArithmeticException -> type=calculation-error, status=422
        // default -> type=internal-error, status=500
        return null;
    }
}

public class Main {
    public static void main(String[] args) {
        ExceptionToProblemMapper mapper = new ExceptionToProblemMapper();

        System.out.println(mapper.map(new IllegalArgumentException("Invalid age value"), "/api/users"));
        System.out.println(mapper.map(new NoSuchElementException("Product not found"), "/api/products/99"));
        System.out.println(mapper.map(new ArithmeticException("Division by zero"), "/api/calculate"));
        System.out.println(mapper.map(new RuntimeException("Unexpected failure"), "/api/orders"));
    }
}

